using System.Net;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// Breaking change: ValidateScopes is now enabled in development by default.
// A Singleton resolving a Scoped service from the root provider throws
// InvalidOperationException. Downgrade to Scoped to match the dependency.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change: HttpClientFactory now uses SocketsHttpHandler by default.
// The cast to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler with the correct handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// Breaking change: Trace-level HttpClientFactory logs now redact all header
// values by default. Allowlist the non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id" &&
        h != "X-Correlation-Id" &&
        h != "Accept" &&
        h != "Content-Type"));

// Breaking change: ForwardedHeadersMiddleware now ignores X-Forwarded-* headers
// from proxies not in KnownProxies or KnownNetworks.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse-proxy addresses
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

